### 2.  `pcapng_stubs.cpp` – C / C++ glue code
```cpp
/* ----------------------------------------------------------------------
   libpcapng OCaml binding – stubs
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE               /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <cstring>
#include <exception>
#include <string>

/* ----------------------------------------------------------------------
   libpcapng C++ API (simplified for the purpose of the binding)
   ---------------------------------------------------------------------- */

/* The real libpcapng library provides a class that parses a pcapng file
   and offers an iterator over its packets.  The exact name of the class and
   its methods may differ – adapt the #include and the class name below to
   match your version of the library. */

#include <pcapng.h>          // <-- change to the real header if needed

/* Minimal wrapper we need – a thin façade around the library’s iterator. */
class PcapngReader {
public:
  explicit PcapngReader(const std::string& filename) {
    // The real library may throw on error; we let the exception propagate.
    parser_ = new pcapng::Parser(filename);
  }
  ~PcapngReader() {
    delete parser_;
  }

  /* Return true and fill `out` when a next packet exists.
     Return false when the file is exhausted. */
  bool next(pcapng::Packet& out) {
    return parser_->next(out);
  }

private:
  pcapng::Parser* parser_;   // whatever the library calls the parser class
};

/* ----------------------------------------------------------------------
   OCaml custom block handling for the abstract type `t`
   ---------------------------------------------------------------------- */

static void pcapng_finalize(value v) {
  /* The custom block stores a pointer to a PcapngReader. */
  PcapngReader* r = *(PcapngReader**)Data_custom_val(v);
  delete r;
}

/* No special comparison / hashing needed – use the defaults. */
static struct custom_operations pcapng_ops = {
  "pcapng.reader",            /* identifier – must be unique */
  pcapng_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_fixed_length_default
};

/* ----------------------------------------------------------------------
   Helper: turn a libpcapng packet into an OCaml `frame` value.
   ---------------------------------------------------------------------- */
static value caml_of_packet(const pcapng::Packet& pkt) {
  CAMLparam0();
  CAMLlocal4(frame_val, ts_val, caplen_val, origlen_val, data_val);

  /* Allocate a 4‑field record (tag 0). */
  frame_val = caml_alloc(4, 0);

  /* 0 – timestamp (float) */
  Store_double_field(frame_val, 0, pkt.timestamp());

  /* 1 – caplen (int) */
  Store_field(frame_val, 1, Val_int(pkt.captured_length()));

  /* 2 – origlen (int) */
  Store_field(frame_val, 2, Val_int(pkt.original_length()));

  /* 3 – data (bytes) */
  int caplen = pkt.captured_length();
  data_val = caml_alloc_string(caplen);
  std::memcpy(String_val(data_val), pkt.data(), caplen);
  Store_field(frame_val, 3, data_val);

  CAMLreturn(frame_val);
}

/* ----------------------------------------------------------------------
   OCaml primitives
   ---------------------------------------------------------------------- */

/* val open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open(value filename_val) {
  CAMLparam1(filename_val);
  CAMLlocal1(res);

  const char* fn = String_val(filename_val);
  try {
    PcapngReader* rdr = new PcapngReader(std::string(fn));
    res = caml_alloc_custom(&pcapng_ops, sizeof(PcapngReader*), 0, 1);
    *(PcapngReader**)Data_custom_val(res) = rdr;
  } catch (const std::exception& e) {
    caml_failwith(e.what());
  } catch (...) {
    caml_failwith("pcapng: unknown error while opening file");
  }

  CAMLreturn(res);
}

/* val close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value handle_val) {
  CAMLparam1(handle_val);
  PcapngReader* rdr = *(PcapngReader**)Data_custom_val(handle_val);
  if (rdr != nullptr) {
    delete rdr;
    *(PcapngReader**)Data_custom_val(handle_val) = nullptr;
  }
  CAMLreturn(Val_unit);
}

/* val iter : t -> (frame -> unit) -> unit */
extern "C" CAMLprim value caml_pcapng_iter(value handle_val,
                                          value callback_val) {
  CAMLparam2(handle_val, callback_val);
  CAMLlocal1(frame_val);

  PcapngReader* rdr = *(PcapngReader**)Data_custom_val(handle_val);
  if (rdr == nullptr) caml_failwith("pcapng: file already closed");

  pcapng::Packet pkt;
  while (rdr->next(pkt)) {
    /* Convert the C++ packet into an OCaml record. */
    frame_val = caml_of_packet(pkt);

    /* Call the user supplied OCaml function. */
    caml_callback(callback_val, frame_val);

    /* If the callback raised, propagate the exception immediately. */
    if (caml_exception_occurred()) {
      caml_raise(caml_exception_result());
    }
  }

  CAMLreturn(Val_unit);
}

/* val with_file : string -> (t -> 'a) -> 'a
   Implemented in OCaml (see the .ml file below).  The stub is only needed
   for the three primitives above, but we expose the name here for completeness. */
```

--------------------------------------------------------------------
### 3.  Tiny `pcapng.ml` – glue that ties the stubs to the interface

You can ship this tiny implementation together with the `.mli` file; it
contains only the `with_file` helper.

```ocaml
(* pcapng.ml – thin wrapper around the C primitives *)

external open_file : string -> t = "caml_pcapng_open"
external close     : t -> unit   = "caml_pcapng_close"
external iter      : t -> (frame -> unit) -> unit = "caml_pcapng_iter"

let with_file filename f =
  let h = open_file filename in
  try
    let r = f h in
    close h;
    r
  with exn ->
    close h;
    raise exn
```

--------------------------------------------------------------------
### 4.  Example usage (OCaml side)

```ocaml
(* test.ml ----------------------------------------------------------- *)
let () =
  Pcapng.with_file "sample.pcapng" (fun rdr ->
    Pcapng.iter rdr (fun frame ->
      Printf.printf "ts=%.6f  caplen=%d  origlen=%d\n%!"
        frame.Pcapng.ts frame.Pcapng.caplen frame.Pcapng.origlen
    )
  )
```

Compile with:

```sh
ocamlc -c pcapng.mli
ocamlc -c pcapng.ml
ocamlopt -c pcapng_stubs.cpp -ccopt -std=c++11   # compile the C++ stub
ocamlopt -o test.exe pcapng.cmx test.ml pcapng_stubs.o -cclib -lpcapng
```

(Replace `-lpcapng` with the actual library name / path.)

--------------------------------------------------------------------
### 5.  Minimal `Makefile` fragment (optional)

```make
OCAMLFLAGS = -thread -I +camlp4
CXXFLAGS   = -O2 -Wall -std=c++11 $(shell ocamlc -config | awk '/cflags/ {print $$2}')
LDFLAGS    = -lpcapng   # <- adjust to your system

all: test.exe

pcapng_stubs.o: pcapng_stubs.cpp pcapng.h
	$(CXX) $(CXXFLAGS) -c $< -o $@

test.exe: pcapng.cmx test.cmx pcapng_stubs.o
	ocamlopt -o $@ $^ $(LDFLAGS)

clean:
	rm -f *.cm[iox] *.o *.exe
```

--------------------------------------------------------------------
### 6.  What the binding provides

* **Safety** – all memory allocated by the C++ library is owned by the OCaml
  runtime (via a custom block) and freed automatically or by an explicit
  `close`.
* **Convenient API** – OCaml code sees a simple record type `frame` and a
  high‑level `iter` function that accepts any OCaml closure.
* **Exception propagation** – if the user‑supplied callback raises, the
  exception bubbles out of `iter` just like a normal OCaml function call.
* **Zero‑copy for the timestamp** – the timestamp is a float, copied directly.
  The packet payload is copied into a fresh OCaml `bytes` value on each
  iteration – this is the usual, safe way to expose binary data to OCaml.

That’s it!  Drop the three source files (`pcapng.mli`, `pcapng.ml`,
`pcapng_stubs.cpp`) into your project, adapt the include/library flags, and
your users will be able to write OCaml code such as the `test.ml` example
above to process every frame in a pcapng file.
